const interest = $json.Interest.toLowerCase().trim();
const feedUrl = `[URL]

return {
  json: {
    interest,
    feedUrl,
    source: 'google_news'
  }
};

// Get all RSS items
const items = $input.all();

// If nothing came in, return empty list
if (items.length === 0) {
  return [];
}

// Date cutoff: last 1 day
const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - 5);

// Filter → Sort → Limit → Return raw RSS items
const articles = items
  .filter(item => {
    const data = item.json;

    // Must have title and link
    if (!data.title || !data.link) return false;

    // Skip error pages
    const title = String(data.title).toLowerCase();
    if (title.includes('404') || title.includes('error')) return false;

    // Skip old articles (if date exists)
    if (data.pubDate) {
      const pubDate = new Date(data.pubDate);
      if (isNaN(pubDate)) return false;
      if (pubDate < cutoffDate) return false;
    }

    return true;
  })
  // Newest first
  .sort((a, b) => {
    const dateA = a.json.pubDate ? new Date(a.json.pubDate).getTime() : 0;
    const dateB = b.json.pubDate ? new Date(b.json.pubDate).getTime() : 0;
    return dateB - dateA;
  })
  // Top 3
  .slice(0, 3)
  // Return EVERYTHING RSS provided
  .map(item => ({
    json: item.json
  }));

return articles;

const url = $json.link;

function isValidShortUrl(result) {
  if (!result || typeof result !== 'string') return false;
  const trimmed = result.trim();
  return trimmed.startsWith('http') && 
         !trimmed.includes('error') && 
         !trimmed.includes('Error') &&
         !trimmed.includes('database') &&
         !trimmed.includes('invalid') &&
         trimmed.length < 100;
}

let tinyResult = null, bitlyResult = null, isgdResult = null;

// 1. Try TinyURL
try {
  tinyResult = await helpers.request({
    method: 'GET',
    url: `[URL]
  });
  if (isValidShortUrl(tinyResult)) {
    return { json: { ...$json, link: tinyResult.trim(), shortener: 'tinyurl' } };
  }
} catch (e) { tinyResult = `ERROR: ${e.message}`; }

// 2. Try Bitly
try {
  const bitlyRes = await helpers.request({
    method: 'POST',
    url: '[URL]',
    headers: {
      'Authorization': `REDACTED_BEARER_TOKEN`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ long_url: url })
  });
  const data = typeof bitlyRes === 'string' ? JSON.parse(bitlyRes) : bitlyRes;
  bitlyResult = data.link || JSON.stringify(data);
  if (data.link && isValidShortUrl(data.link)) {
    return { json: { ...$json, link: data.link, shortener: 'bitly' } };
  }
} catch (e) { bitlyResult = `ERROR: ${e.message}`; }

// 3. Try is.gd
try {
  isgdResult = await helpers.request({
    method: 'GET',
    url: `[URL]
  });
  if (isValidShortUrl(isgdResult)) {
    return { json: { ...$json, link: isgdResult.trim(), shortener: 'isgd' } };
  }
} catch (e) { isgdResult = `ERROR: ${e.message}`; }

// 4. Fallback + debug
return { json: { 
  ...$json, 
  link: url, 
  shortener: 'original',
  debug: { tinyResult, bitlyResult, isgdResult }
}};
